const express = require('express');
const jwt = require('jsonwebtoken');

const app = express();
app.use(express.json());

const clientSecret = 'your_client_secret';
const clientId = 'your_client_id';

app.post('/login', (req, res) => {
  const idToken = req.body.id_token;
  if (!idToken) return res.status(401).send('Missing ID token');

  jwt.verify(idToken, clientSecret, { algorithms: ['RS256'] }, (err, decoded) => {
    if (err) return res.status(401).send('Invalid ID token');
    const claims = decoded;
    // Create user session
    req.session.userId = claims.sub;
    req.session.userEmail = claims.email;

    res.json({ message: 'Login successful' });
  });
});

app.get('/login/callback', (req, res) => {
  if (!req.query.code) return res.status(401).send('Missing code');
  const tokenUrl = `https://your_openid_provider.com/token`;
  const tokenBody = {
    grant_type: 'authorization_code',
    code: req.query.code,
    redirect_uri: `${process.env.HOST}/login/callback`,
    client_id: clientId
  };

  fetch(tokenUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: new URLSearchParams(tokenBody).toString()
  })
    .then(response => response.json())
    .then(data => {
      const idToken = data.id_token;
      jwt.decode(idToken, { complete: true }, (err, decoded) => {
        if (err) return res.status(401).send('Invalid ID token');
        const claims = decoded.payload;
        // Create user session
        req.session.userId = claims.sub;
        req.session.userEmail = claims.email;

        res.redirect('/');
      });
    })
    .catch(error => console.error(error));
});

app.listen(process.env.PORT, () => {
  console.log(`Server listening on port ${process.env.PORT}`);
});